 1	import React from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Label, LabelGroup } from '@patternfly/react-core';
 6	
 7	import { extractKeyValueFromLabel, transformKeyValueToLabel } from './utils';
 8	
 9	import './SelectorLabelMatchGroup.scss';
10	
11	type SelectorLabelMatchGroupProps = {
12	  isVMILabel?: boolean;
13	  labels: { [key: string]: string };
14	  setLabels?: React.Dispatch<
15	    React.SetStateAction<{
16	      [key: string]: string;
17	    }>
18	  >;
19	};
20	
21	const SelectorLabelMatchGroup: React.FC<SelectorLabelMatchGroupProps> = ({
22	  isVMILabel,
23	  labels,
24	  setLabels,
25	}) => {
26	  const { t } = useKubevirtTranslation();
27	
28	  const onDeleteLabel = (key: string) => () =>
29	    setLabels((prevLabels) => {
30	      const updatedLabels = { ...prevLabels };
31	      delete updatedLabels[key];
32	      return updatedLabels;
33	    });
34	
35	  const onEditLabel = (key: string) => (newText: string) => {
36	    const [newKey, newValue] = extractKeyValueFromLabel(newText);
37	    if (!!newKey && !!newValue) {
38	      setLabels((prevLabels) => {
39	        const updatedLabels = { ...prevLabels };
40	        delete updatedLabels[key];
41	        updatedLabels[newKey] = newValue;
42	        return updatedLabels;
43	      });
44	    }
45	  };
46	
47	  const onAddLabel = (newText: string) => {
48	    const [newKey, newValue] = extractKeyValueFromLabel(newText);
49	    if (!!newKey && !!newValue) {
50	      setLabels((prevLabels) => ({ ...prevLabels, [newKey]: newValue }));
51	    }
52	  };
53	
54	  return (
55	    <>
56	      <LabelGroup className="mp-match-label-group" isEditable numLabels={10}>
57	        {Object.keys(labels || {})?.map((key) => {
58	          return (
59	            <Label
60	              className={classNames({ 'kv-migration-policy__label-vm': isVMILabel })}
61	              color={isVMILabel ? 'grey' : 'blue'}
62	              isEditable
63	              key={key}
64	              onClose={onDeleteLabel(key)}
65	              onEditComplete={(_, val) => onEditLabel(key)(val)}
66	            >
67	              {transformKeyValueToLabel(key, labels[key])}
68	            </Label>
69	          );
70	        })}
71	        <Label
72	          color="blue"
73	          isEditable
74	          onEditComplete={(_, val) => onAddLabel(val)}
75	          variant="outline"
76	        >
77	          {t('Enter key=value')}
78	        </Label>
79	      </LabelGroup>
80	    </>
81	  );
82	};
83	
84	export default SelectorLabelMatchGroup;

